        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new SpreadExchOrderMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[SpreadExchOrderMessage](sbeTemplateId=");
            builder.Append(SpreadExchOrderMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(SpreadExchOrderMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != SpreadExchOrderMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(SpreadExchOrderMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != SpreadExchOrderMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(SpreadExchOrderMessage.BlockLength);
            builder.Append("):");

            builder.Append("FromCache=");
            builder.Append(this.FromCache);
            builder.Append('|');
            builder.Append("AllOrNone=");
            builder.Append(this.AllOrNone);
            builder.Append('|');
            builder.Append("FlipSide=");
            builder.Append(this.FlipSide);
            builder.Append('|');
            builder.Append("IsPriceValid=");
            builder.Append(this.IsPriceValid);
            builder.Append('|');
            builder.Append("Exch=");
            builder.Append(this.Exch);
            builder.Append('|');
            builder.Append("FirmType=");
            builder.Append(this.FirmType);
            builder.Append('|');
            builder.Append("MarketQualifier=");
            builder.Append(this.MarketQualifier);
            builder.Append('|');
            builder.Append("OrderStatus=");
            builder.Append(this.OrderStatus);
            builder.Append('|');
            builder.Append("OrderType=");
            builder.Append(this.OrderType);
            builder.Append('|');
            builder.Append("TimeInForce=");
            builder.Append(this.TimeInForce);
            builder.Append('|');
            builder.Append("BaseStrategy=");
            builder.Append(this.BaseStrategy);
            builder.Append('|');
            builder.Append("OrigOrderSize=");
            builder.Append(this.OrigOrderSize);
            builder.Append('|');
            builder.Append("OrderSize=");
            builder.Append(this.OrderSize);
            builder.Append('|');
            builder.Append("Price=");
            builder.Append(this.Price);
            builder.Append('|');
            builder.Append("DgwTimestamp=");
            builder.Append(this.DgwTimestamp);
            builder.Append('|');
            builder.Append("SrcTimestamp=");
            builder.Append(this.SrcTimestamp);
            builder.Append('|');
            builder.Append("NetTimestamp=");
            builder.Append(this.NetTimestamp);
            builder.Append('|');
            builder.Append("Timestamp=");
            builder.Append(this.Timestamp);
            builder.Append('|');
            builder.Append("Underlying=");
            builder.Append("'");
            for (int i = 0; i < UnderlyingLength && this.GetUnderlying(i) > 0; ++i)
            {
                builder.Append((char)this.GetUnderlying(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("SpreadSymbol=");
            builder.Append('\'').Append(GetSpreadSymbol()).Append('\'');
            builder.Append('|');
            builder.Append("ClearingAccount=");
            builder.Append('\'').Append(GetClearingAccount()).Append('\'');
            builder.Append('|');
            builder.Append("ClearingFirm=");
            builder.Append('\'').Append(GetClearingFirm()).Append('\'');
            builder.Append('|');
            builder.Append("OrderID=");
            builder.Append('\'').Append(GetOrderID()).Append('\'');
            builder.Append('|');
            builder.Append("SpreadKey=");
            builder.Append('\'').Append(GetSpreadKey()).Append('\'');
            builder.Append('|');
            builder.Append("SpreadId=");
            builder.Append('\'').Append(GetSpreadId()).Append('\'');
            builder.Append('|');
            builder.Append("SpreadDescription=");
            builder.Append('\'').Append(GetSpreadDescription()).Append('\'');

            this.Limit = originalLimit;

        }
